#!/usr/bin/env node
// Extract memory values from an ELF binary.
// Loads each PT_LOAD segment at its virtual address and emits every
// 4-byte little-endian word of file-backed memory as address -> integer.
'use strict';
const fs = require('fs');

const path = process.argv[2];
if (!path) {
  process.stderr.write('usage: node extract.js <binary>\n');
  process.exit(1);
}
const buf = fs.readFileSync(path);

// --- ELF header ---
if (buf.length < 64 || buf.readUInt32LE(0) !== 0x464c457f) {
  process.stderr.write('not an ELF file\n');
  process.exit(1);
}
const ei_class = buf[4]; // 1=32bit, 2=64bit
const is64 = ei_class === 2;

const out = {};

if (is64) {
  const e_phoff = Number(buf.readBigUInt64LE(0x20));
  const e_phentsize = buf.readUInt16LE(0x36);
  const e_phnum = buf.readUInt16LE(0x38);

  for (let i = 0; i < e_phnum; i++) {
    const off = e_phoff + i * e_phentsize;
    const p_type = buf.readUInt32LE(off);
    if (p_type !== 1) continue; // PT_LOAD
    const p_offset = Number(buf.readBigUInt64LE(off + 0x08));
    const p_vaddr = Number(buf.readBigUInt64LE(off + 0x10));
    const p_filesz = Number(buf.readBigUInt64LE(off + 0x20));
    emit(p_offset, p_vaddr, p_filesz);
  }
} else {
  const e_phoff = buf.readUInt32LE(0x1c);
  const e_phentsize = buf.readUInt16LE(0x2a);
  const e_phnum = buf.readUInt16LE(0x2c);

  for (let i = 0; i < e_phnum; i++) {
    const off = e_phoff + i * e_phentsize;
    const p_type = buf.readUInt32LE(off);
    if (p_type !== 1) continue; // PT_LOAD
    const p_offset = buf.readUInt32LE(off + 0x04);
    const p_vaddr = buf.readUInt32LE(off + 0x08);
    const p_filesz = buf.readUInt32LE(off + 0x10);
    emit(p_offset, p_vaddr, p_filesz);
  }
}

function emit(p_offset, p_vaddr, p_filesz) {
  // Only full 4-byte words that are fully file-backed.
  const words = Math.floor(p_filesz / 4);
  for (let w = 0; w < words; w++) {
    const fo = p_offset + w * 4;
    if (fo + 4 > buf.length) break;
    const addr = p_vaddr + w * 4;
    out[addr] = buf.readUInt32LE(fo);
  }
}

process.stdout.write(JSON.stringify(out));

